var b="url",c="物料仓库.html",d="generationDate",e=new Date(1781494386344.98),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="08dfcd9407414d568314cf304768ffa0",v="type",w="Axure:Page",x="物料仓库",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="cdca5250521a4ccc93c52af6a30b213a",E="label",F="删除",G="说明",H="<p><span>1.点击时则校验[仓库管理&gt;&gt;物料库存：库存明细]中是否存在'唯一码'使用勾选的“库位编码”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.不存在：弹窗进行二次确认</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.存在</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.返回Toast提示：存在物料的库位(XXX)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.其中，XXX为查询到的库位编码</span></p>",I="2",J="d5d01685a5de4404af9f48c5bedeb3ee",K="导入",L="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">EXCEL表头</span></p><p><span>1.仓库名称(必填)</span></p><p><span>2.库位编码(必填)</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">导入校验</span></p><p><span>1.校验“仓库名称”是否存在空的行，Toast提示：请填写仓库名称</span></p><p><span>2.校验“库位编码”是否存在空的行，Toast提示：请填写库位编码</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">导入处理</span></p><p><span>1.作增量导入</span></p><p><span>2.若“仓库名称”已存在，校验“库位编码”是否已存在于该仓库下</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; 2.1 已存在的库位编码：忽略改行</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; 3.2 不存在的库位编码：将库位添加至对应仓库下</span></p><p><span>3.若“仓库名称”不存在</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; 3.1 自动创建仓库(“仓库编码”自动生成：'WLCK'+'2位流水')</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; 3.2 将库位添加至该仓库下</span></p><p><span>4.以当前操作人和操作时间作为创建人、创建时间</span></p>",M="3",N="ef76582b7f1f4f778a2363534bd6ef85",O="导出",P="<p><span>EXCEL表头</span></p><p><span>1.仓库编码</span></p><p><span>2.仓库名称</span></p><p><span>3.库位编码</span></p><p><span>4.创建人</span></p><p><span>5.创建时间</span></p>",Q="4",R="bf8c11b312a745ccaae036fd55ef3bb1",S="大屏链接：",T="<p><span>1.链接地址由创建仓库时对应生成</span></p><p><span>2.大屏样式：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">绿底驾驶舱</span></p>",U="5",V="98e85826dae9421a93fcba817826ce43",W="保存",X="<p><span>1.校验“仓库编码”是否为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.为空：自动生成 'WLCK'+'2位流水'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.不为空：校验唯一，否则Toast提示：已存在的仓库编码</span></p><p><span>2.校验“仓库编码”是否为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.为空：Toast提示：请填写仓库名称</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.不为空：校验“仓库名称”唯一，否则Toast提示：已存在的仓库名称</span></p>",Y="6",Z="89d0db773bd64b5aa699b9282602af1a",ba="<p><span>1.校验“库位编码”是否为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.为空：Toast提示：请填写库位编码</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.不为空：校验“库位编码”在当前仓库下唯一，否则Toast提示：已存在的库位</span></p>",bb="7",bc="a6343fcca2184793a6b5f608604291fd",bd="* 库位编码",be="<p><span>左侧前缀为当前仓库对应的“仓库编码”</span></p>",bf="8",bg="cef63a0b338e45e1b42dce7b68b809c7",bh="操作",bi="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">打印</span></p><p><span>1.样式如右侧图所示</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">删除</span></p><p><span>1.点击时则校验[仓库管理&gt;&gt;物料库存：库存明细]中是否存在'唯一码'使用当前库位</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.不存在：弹窗进行二次确认</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.存在：删除失败；返回Toast提示：该库位上存在物料库存，无法删除</span></p>",bj="style",bk="baseStyle",bl="627587b6038d43cca051c114ac41ad32",bm="pageAlignment",bn="center",bo="fill",bp="fillType",bq="solid",br="color",bs=0xFFFFFFFF,bt="image",bu="imageAlignment",b